mapper.select:
SELECT c.challenge_id AS challengeId, c.user_id AS userId, c.mode_type AS modeType, c.title AS title, c.description AS description, c.difficulty AS difficulty, c.period_days AS periodDays, c.max_participants AS maxParticipants,
(SELECT COUNT(*) FROM user_challenge uc WHERE uc.challenge_id = c.challenge_id AND uc.status = 'PROGRESS') AS currentParticipants
FROM challenge c WHERE c.challenge_id = #{challengeId}
